188.          "eighteen", "nineteen"];
189. 
190.     private static readonly string[] TensMap =
191.         ["", "", "twenty", "thirty", "forty", "fifty", "sixty", "seventy", "eighty", "ninety"];
192. 
193.     // Correct pattern: static readonly with all lookup data
194.     private static readonly (long divisor, string name)[] Groups =
195.     [
196.         (1_000_000_000_000, "trillion"),
197.         (1_000_000_000, "billion"),
