207.         {
208.             return UnitsMap[0];
209.         }
210. 
211.         if (number < 0)
212.         {
213.             return $"minus {Convert(-number)}";
214.         }
215. 
216.         // Correct: uses pre-sized list
217.         var parts = new List<string>(4);
218. 
219.         foreach (var (divisor, name) in Groups)
220.         {
221.             if (number / divisor > 0)
222.             {
