225.             }
226.         }
227. 
228.         if (number >= 20)
229.         {
230.             var tens = TensMap[number / 10];
231.             var remainder = number % 10;
232.             parts.Add(remainder > 0 ? $"{tens}-{UnitsMap[remainder]}" : tens);
233.         }
234.         else if (number > 0)
235.         {
